// src/pages/KhaiBaoCoSo.js
import React, { useState } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx'; // Import thư viện xlsx
import { saveAs } from 'file-saver'; // Import thư viện file-saver
import './KhaiBaoCoSo.css'; // Import file CSS

function KhaiBaoCoSo() {
  const [form, setForm] = useState({
    tenCoSo: '',
    diaChi: '',
    vido: '',
    kinhdo: '',
    tinhThanhPho: '', // Đã thêm
    xaPhuong: '',     // Đã thêm
    tenChuCoSo: '',
    namSinh: '',          // Đã thêm
    soCanCuoc: '',        // Đã thêm
    ngayCap: '',          // Đã thêm
    noiCap: '',           // Đã thêm
    soDienThoai: '',
    diaChiNguoiDaiDien: '', // Đã thêm
    mucDichNuoi: '',      // Đã thêm
    hinhThucNuoi: '',     // Đã thêm
    maSoCoSo: '',         // Đã thêm
    hoTenKinhDoanhGo: '', // Đã thêm
    emailNguoiDaiDien: '',
  });
  const [excelFile, setExcelFile] = useState(null); // State để lưu file Excel đã chọn
  const [successMessage, setSuccessMessage] = useState('');
  const [errorMessage, setErrorMessage] = useState('');
  const [importStatus, setImportStatus] = useState(''); // Trạng thái import
  const [exportStatus, setExportStatus] = useState(''); // Trạng thái xuất file

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file && (file.type === "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" || file.type === "application/vnd.ms-excel")) {
      setExcelFile(file);
      setErrorMessage('');
    } else {
      setExcelFile(null);
      setErrorMessage('Vui lòng chọn một tệp Excel hợp lệ (.xlsx hoặc .xls).');
    }
  };

  const handleImportExcel = async () => {
    if (!excelFile) {
      setErrorMessage('Vui lòng chọn tệp Excel để nhập.');
      return;
    }

    setSuccessMessage('');
    setErrorMessage('');
    setImportStatus('Đang đọc dữ liệu từ tệp Excel...');

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = new Uint8Array(e.target.result);
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0]; // Lấy sheet đầu tiên
        const worksheet = workbook.Sheets[sheetName];
        const jsonData = XLSX.utils.sheet_to_json(worksheet); // Chuyển đổi sang JSON

        setImportStatus(`Đã đọc ${jsonData.length} dòng dữ liệu. Đang gửi lên máy chủ...`);

        const token = localStorage.getItem('token');
        if (!token) {
          setErrorMessage('Bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
          setImportStatus('');
          return;
        }

        const formattedData = jsonData.map(row => ({
            tenCoSo: row['Tên Cơ Sở'] || '',
            diaChi: row['Địa Chỉ'] || '',
            vido: row['Vĩ Độ'] ? String(row['Vĩ Độ']) : '',
            kinhdo: row['Kinh Độ'] ? String(row['Kinh Độ']) : '',
            tinhThanhPho: row['Tỉnh/Thành Phố'] || '',
            xaPhuong: row['Xã/Phường'] || '',
            tenChuCoSo: row['Tên Chủ Cơ Sở'] || '',
            namSinh: row['Năm Sinh'] ? String(row['Năm Sinh']) : '',
            soCanCuoc: row['Số CCCD/Hộ Chiếu'] ? String(row['Số CCCD/Hộ Chiếu']) : '',
            ngayCap: row['Ngày Cấp'] ? new Date(row['Ngày Cấp']).toISOString().split('T')[0] : '', // Chuyển đổi ngày tháng
            noiCap: row['Nơi Cấp'] || '',
            soDienThoai: row['Số Điện Thoại'] ? String(row['Số Điện Thoại']) : '',
            diaChiNguoiDaiDien: row['Địa Chỉ Người Đại Diện'] || '',
            mucDichNuoi: row['Mục Đích Nuôi'] || '',
            hinhThucNuoi: row['Hình Thức Nuôi'] || '',
            maSoCoSo: row['Mã Số Cơ Sở'] ? String(row['Mã Số Cơ Sở']) : '',
            hoTenKinhDoanhGo: row['Họ Tên Kinh Doanh Gỗ'] || '',
            emailNguoiDaiDien: row['Email Người Đại Diện'] || '',
        }));

        const response = await axios.post(
          'http://localhost:10000/api/farms/batch-import',
          { farms: formattedData },
          {
            headers: {
              Authorization: `Bearer ${token}`,
              'Content-Type': 'application/json'
            }
          }
        );

        console.log('Batch import success:', response.data);
        setSuccessMessage(`Đã nhập thành công ${response.data.importedCount} cơ sở. ${response.data.failedCount > 0 ? `(${response.data.failedCount} thất bại).` : ''}`);
        setErrorMessage(response.data.errors.length > 0 ? `Chi tiết lỗi: ${response.data.errors.join('; ')}` : '');
        setImportStatus('');
        setExcelFile(null); // Xóa file đã chọn
      } catch (error) {
        setErrorMessage('Đã xảy ra lỗi khi nhập tệp Excel. Vui lòng kiểm tra định dạng tệp và thử lại.');
        setImportStatus('');
        console.error('Error importing Excel:', error.response?.data || error.message);

        if (error.response && error.response.data && error.response.data.message) {
          setErrorMessage(`Đã xảy ra lỗi: ${error.response.data.message}`);
        }
      }
    };
    reader.readAsArrayBuffer(excelFile);
  };

  const handleExportExcel = async () => {
    setSuccessMessage('');
    setErrorMessage('');
    setExportStatus('Đang tải dữ liệu và tạo tệp Excel...');

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setErrorMessage('Bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
        setExportStatus('');
        return;
      }

      const response = await axios.get(
        'http://localhost:10000/api/farms',
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      const farms = response.data.data;

      if (!farms || farms.length === 0) {
        setErrorMessage('Không có dữ liệu cơ sở để xuất.');
        setExportStatus('');
        return;
      }

      const dataToExport = farms.map(farm => ({
        'ID': farm._id,
        'Tên Cơ Sở': farm.tenCoSo,
        'Địa Chỉ': farm.diaChi,
        'Vĩ Độ': farm.vido,
        'Kinh Độ': farm.kinhdo,
        'Tỉnh/Thành Phố': farm.tinhThanhPho,
        'Xã/Phường': farm.xaPhuong,
        'Tên Chủ Cơ Sở': farm.tenChuCoSo,
        'Năm Sinh': farm.namSinh,
        'Số CCCD/Hộ Chiếu': farm.soCanCuoc,
        'Ngày Cấp': farm.ngayCap ? new Date(farm.ngayCap).toLocaleDateString('vi-VN') : '',
        'Nơi Cấp': farm.noiCap,
        'Số Điện Thoại': farm.soDienThoai,
        'Địa Chỉ Người Đại Diện': farm.diaChiNguoiDaiDien,
        'Email Người Đại Diện': farm.emailNguoiDaiDien,
        'Mục Đích Nuôi': farm.mucDichNuoi,
        'Hình Thức Nuôi': farm.hinhThucNuoi,
        'Mã Số Cơ Sở': farm.maSoCoSo,
        'Họ Tên Kinh Doanh Gỗ': farm.hoTenKinhDoanhGo,
        'Ngày Tạo': new Date(farm.createdAt).toLocaleDateString('vi-VN'),
      }));

      const worksheet = XLSX.utils.json_to_sheet(dataToExport);
      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, 'DanhSachCoSo');

      const excelBuffer = XLSX.write(workbook, { bookType: 'xlsx', type: 'array' });
      const data = new Blob([excelBuffer], { type: 'application/octet-stream' });
      saveAs(data, 'DanhSachCoSo.xlsx');

      setSuccessMessage('Dữ liệu cơ sở đã được xuất ra tệp Excel thành công!');
      setExportStatus('');
    } catch (error) {
      setErrorMessage('Đã xảy ra lỗi khi xuất tệp Excel. Vui lòng thử lại.');
      setExportStatus('');
      console.error('Error exporting Excel:', error.response?.data || error.message);

      if (error.response && error.response.data && error.response.data.message) {
        setErrorMessage(`Đã xảy ra lỗi: ${error.response.data.message}`);
      }
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSuccessMessage('');
    setErrorMessage('');
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setErrorMessage('Bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
        return;
      }

      const response = await axios.post(
        'http://localhost:10000/api/farms',
        form,
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      console.log('Success:', response.data);
      setSuccessMessage('Thông tin cơ sở đã được lưu thành công!');
      setForm({ // Reset form sau khi thành công
        tenCoSo: '',
        diaChi: '',
        vido: '',
        kinhdo: '',
        tinhThanhPho: '',
        xaPhuong: '',
        tenChuCoSo: '',
        namSinh: '',
        soCanCuoc: '',
        ngayCap: '',
        noiCap: '',
        soDienThoai: '',
        diaChiNguoiDaiDien: '',
        mucDichNuoi: '',
        hinhThucNuoi: '',
        maSoCoSo: '',
        hoTenKinhDoanhGo: '',
        emailNguoiDaiDien: '',
      });
    } catch (error) {
      setErrorMessage('Đã xảy ra lỗi khi lưu thông tin. Vui lòng thử lại.');
      console.error('Error saving farm:', error.response?.data || error.message);

      if (error.response && error.response.data && error.response.data.errors) {
        const validationErrors = Object.values(error.response.data.errors).map(err => err.message).join('; ');
        setErrorMessage(`Lỗi xác thực: ${validationErrors}`);
      } else if (error.response && error.response.data && error.response.data.message) {
        setErrorMessage(`Đã xảy ra lỗi: ${error.response.data.message}`);
      }
    }
  };

  return (
    <div className="khai-bao-container">
      <h1>Khai báo cơ sở</h1>
      {successMessage && <p className="success-message">{successMessage}</p>}
      {errorMessage && <p className="error-message">{errorMessage}</p>}
      {importStatus && <p className="import-status">{importStatus}</p>}
      {exportStatus && <p className="export-status">{exportStatus}</p>}

      {/* Phần nhập Excel */}
      <section className="khai-bao-section">
        <h2>Nhập dữ liệu từ Excel</h2>
        <div className="form-group">
          <label htmlFor="excelUpload">Chọn tệp Excel:</label>
          <input type="file" id="excelUpload" accept=".xlsx, .xls" onChange={handleFileChange} />
        </div>
        <button onClick={handleImportExcel} disabled={!excelFile} className="submit-button">
          Nhập dữ liệu từ Excel
        </button>
        <p>
          Để nhập hàng loạt, tệp Excel của bạn phải có các cột với tên chính xác:
          "Tên Cơ Sở", "Địa Chỉ", "Vĩ Độ", "Kinh Độ", "Tỉnh/Thành Phố", "Xã/Phường",
          "Tên Chủ Cơ Sở", "Năm Sinh", "Số CCCD/Hộ Chiếu", "Ngày Cấp", "Nơi Cấp",
          "Số Điện Thoại", "Địa Chỉ Người Đại Diện", "Mục Đích Nuôi", "Hình Thức Nuôi",
          "Mã Số Cơ Sở", "Họ Tên Kinh Doanh Gỗ", "Email Người Đại Diện".
        </p>
      </section>

      <hr />

      {/* Phần xuất Excel */}
      <section className="khai-bao-section">
        <h2>Xuất dữ liệu ra Excel</h2>
        <button onClick={handleExportExcel} className="submit-button">
          Xuất tất cả cơ sở ra Excel
        </button>
        <p>
          Thao tác này sẽ tải về một tệp Excel chứa tất cả thông tin cơ sở hiện có trong hệ thống.
        </p>
      </section>

      <hr />

      {/* Phần Khai báo từng cơ sở (form cũ) */}
      <form onSubmit={handleSubmit}>
        <section className="khai-bao-section">
          <h2>Thông tin cơ sở (Khai báo từng cái)</h2>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="tenCoSo">Tên cơ sở:</label>
              <input type="text" id="tenCoSo" name="tenCoSo" value={form.tenCoSo} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="tinhThanhPho">Tỉnh (Thành phố):</label>
              <input type="text" id="tinhThanhPho" name="tinhThanhPho" value={form.tinhThanhPho} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="xaPhuong">Xã (Phường):</label>
              <input type="text" id="xaPhuong" name="xaPhuong" value={form.xaPhuong} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="diaChi">Địa chỉ:</label>
              <input type="text" id="diaChi" name="diaChi" value={form.diaChi} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="vido">Vĩ độ:</label>
              <input type="text" id="vido" name="vido" value={form.vido} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="kinhdo">Kinh độ:</label>
              <input type="text" id="kinhdo" name="kinhdo" value={form.kinhdo} onChange={handleChange} />
            </div>
          </div>
        </section>
        <section className="khai-bao-section">
          <h2>Người đại diện</h2>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="tenChuCoSo">Họ và tên:</label>
              <input type="text" id="tenChuCoSo" name="tenChuCoSo" value={form.tenChuCoSo} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="namSinh">Năm sinh:</label>
              <input type="text" id="namSinh" name="namSinh" value={form.namSinh} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="soCanCuoc">Số CCCD/Hộ chiếu:</label>
              <input type="text" id="soCanCuoc" name="soCanCuoc" value={form.soCanCuoc} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="ngayCap">Ngày cấp:</label>
              <input type="date" id="ngayCap" name="ngayCap" value={form.ngayCap} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="noiCap">Nơi cấp:</label>
              <input type="text" id="noiCap" name="noiCap" value={form.noiCap} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="soDienThoai">Số điện thoại:</label>
              <input type="tel" id="soDienThoai" name="soDienThoai" value={form.soDienThoai} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="diaChiNguoiDaiDien">Địa chỉ người đại diện:</label>
              <input type="text" id="diaChiNguoiDaiDien" name="diaChiNguoiDaiDien" value={form.diaChiNguoiDaiDien} onChange={handleChange} />
            </div>
            <div className="form-group">
              <label htmlFor="emailNguoiDaiDien">Email người đại diện:</label>
              <input type="email" id="emailNguoiDaiDien" name="emailNguoiDaiDien" value={form.emailNguoiDaiDien} onChange={handleChange} />
            </div>
          </div>
        </section>
        <section className="khai-bao-section">
          <h3>Cơ sở gây nuôi</h3>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="mucDichNuoi">Mục đích nuôi:</label>
              <input type="text" id="mucDichNuoi" name="mucDichNuoi" value={form.mucDichNuoi} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="hinhThucNuoi">Hình thức nuôi:</label>
              <input type="text" id="hinhThucNuoi" name="hinhThucNuoi" value={form.hinhThucNuoi} onChange={handleChange} required />
            </div>
            <div className="form-group">
              <label htmlFor="maSoCoSo">Mã số cơ sở:</label>
              <input type="text" id="maSoCoSo" name="maSoCoSo" value={form.maSoCoSo} onChange={handleChange} required />
            </div>
          </div>
        </section>
        <section className="khai-bao-section">
          <h4>Cơ sở kinh doanh, chế biến gỗ</h4>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="hoTenKinhDoanhGo">Họ và tên chủ cơ sở kinh doanh, chế biến gỗ:</label>
              <input type="text" id="hoTenKinhDoanhGo" name="hoTenKinhDoanhGo" value={form.hoTenKinhDoanhGo} onChange={handleChange} required />
            </div>
          </div>
        </section>
        <button type="submit" className="submit-button">Lưu thông tin</button>
      </form>
    </div>
  );
}

export default KhaiBaoCoSo;
